import React, { useState, useEffect } from 'react';
import NavBar from '../../components/NavBar/NavBar';
import Waveform from '../../components/Waveform/Waveform';
import './Record.css';

function WhileRecord({ onPause, onSave, maxDuration = 180 }) {
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setElapsed((prev) => {
        if (prev >= maxDuration) { clearInterval(interval); return maxDuration; }
        return prev + 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [maxDuration]);

  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  return (
    <div className="screen">
      <NavBar active="record" />
      <div className="screen-content">
        <Waveform />
        <p className="timer">{formatTime(elapsed)}/{formatTime(maxDuration)}</p>
        <div className="btn-row">
          <button className="btn btn-pause" onClick={() => onPause(elapsed)}>PAUSE</button>
          <button className="btn btn-save" onClick={() => onSave(elapsed)}>SAVE</button>
        </div>
      </div>
    </div>
  );
}

export default WhileRecord;
